import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Cpu, Terminal, Lock } from 'lucide-react';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const { login, loading } = useAuth();
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    if (!email || !password) return toast.error('FIELDS_REQUIRED');

    const toastId = toast.loading('INITIALIZING_SECURE_HANDSHAKE...');
    try {
      await login(email, password);
      toast.success('ACCESS_GRANTED', { id: toastId });
      navigate('/dashboard');
    } catch (error) {
      toast.error('GATE_REJECTION: INVALID_CREDENTIALS', { id: toastId });
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-6 bg-transparent">
      <div className="w-full max-w-md cyber-card relative overflow-hidden">
        {/* Decorative Top Glow */}
        <div className="absolute -top-24 -left-24 w-48 h-48 bg-purple-600/20 blur-[100px]" />

        <div className="text-center mb-10">
          <div className="flex justify-center mb-4 text-purple-400">
            <Cpu size={42} className="animate-pulse" />
          </div>
          <h1 className="text-3xl font-light tracking-tight text-white mb-2">Welcome Back</h1>
          <p className="text-white/40 text-[10px] uppercase tracking-[0.25em]">Sign in to access your node</p>
        </div>

        <form onSubmit={handleLogin} className="space-y-6">
          <div className="space-y-2">
            <label className="flex items-center gap-2 text-[10px] text-purple-400 font-bold uppercase tracking-widest ml-1">
              <Terminal size={12} /> Email Address
            </label>
            <input
              type="email"
              className="cyber-input"
              placeholder="operator@finify.ai"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />
          </div>

          <div className="space-y-2">
            <label className="flex items-center gap-2 text-[10px] text-purple-400 font-bold uppercase tracking-widest ml-1">
              <Lock size={12} /> Master Key
            </label>
            <input
              type="password"
              className="cyber-input"
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            className={`cyber-btn mt-6 ${loading ? 'opacity-60 cursor-not-allowed' : ''}`}
          >
            {loading ? 'SYNCHRONIZING...' : 'Sign In'}
          </button>
        </form>

        <p className="text-center mt-10 text-[10px] text-white/30 uppercase tracking-[0.25em]">
          Don't have an account? <Link to="/register" className="text-purple-400 hover:underline">Sign Up</Link>
        </p>
      </div>
    </div>
  );
};

export default LoginPage;
